# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import pymysql
import json

def lambda_handler(event, context):
    # Database configuration
    db_config = {
        'host': 'your-rds-endpoint',
        'user': 'your-username',
        'password': 'your-password',
        'database': 'your-database'
    }
    
    # Connect to the RDS MySQL database
    connection = pymysql.connect(**db_config)
    
    try:
        with connection.cursor() as cursor:
            # Extract search parameters from the event
            params = {
                'name': event.get('queryStringParameters', {}).get('name'),
                'category': event.get('queryStringParameters', {}).get('category'),
                'price_min': event.get('queryStringParameters', {}).get('price_min'),
                'price_max': event.get('queryStringParameters', {}).get('price_max')
            }
            
            # Construct SQL query dynamically based on provided parameters
            sql = "SELECT * FROM products WHERE 1=1"
            where_clause = []
            if params['name']:
                where_clause.append(f" name LIKE '%{params['name']}%'")
            if params['category']:
                where_clause.append(f" category = '{params['category']}'")
            if params['price_min'] and params['price_max']:
                where_clause.append(f" price BETWEEN {params['price_min']} AND {params['price_max']}")
            
            if where_clause:
                sql += " AND " + " AND ".join(where_clause)
            
            # Execute the query
            cursor.execute(sql)
            result = cursor.fetchall()
            
            # Convert results to JSON serializable format
            products = [dict(zip([desc[0] for desc in cursor.description], row)) for row in result]
            
            return {
                'statusCode': 200,
                'headers': {
                    'Content-Type': 'application/json'
                },
                'body': json.dumps(products)
            }
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }
    finally:
        connection.close()